 10	import { DeploymentModel } from '@odf/shared/models';
 11	import { getName } from '@odf/shared/selectors';
 12	import { DeploymentKind, K8sResourceKind } from '@odf/shared/types';
 13	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 14	import { resourcePathFromModel } from '@odf/shared/utils';
 15	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
 16	import { useNavigate } from 'react-router-dom-v5-compat';
 17	import { Alert, Button, Modal, ModalVariant } from '@patternfly/react-core';
 18	import { getAttachOBCPatch } from '../../utils';
 19	import './attach-deployment.scss';
 20	
 21	type AttachDeploymentToOBCModalProps = CommonModalProps<{
 22	  resource: K8sResourceKind;
 23	  namespace: string;
 24	}>;
 25	
 26	const AttachDeploymentToOBCModal: React.FC<AttachDeploymentToOBCModalProps> = (
 27	  props
 28	) => {
 29	  const { t } = useCustomTranslation();
 30	  const [requestDeployment, setRequestedDeployment] =
 31	    React.useState<DeploymentKind>(null);
 32	  const [inProgress, setProgress] = React.useState(false);
 33	  const [errorMessage, setErrorMessage] = React.useState('');
 34	  const {
 35	    closeModal,
 36	    isOpen,
 37	    extraProps: { resource, namespace },
 38	  } = props;
 39	
 40	  const navigate = useNavigate();
 41	
 42	  // Deployments
 43	
 44	  const deploymentResource = {
 45	    kind: DeploymentModel.kind,
 46	    namespaced: true,
 47	    isList: true,
 48	    namespace,
 49	  };
 50	
 51	  const obcName = getName(resource);
 52	
 53	  const submit: React.FormEventHandler<EventTarget> = (e) => {
 54	    setProgress(true);
 55	    e.preventDefault();
 56	    k8sPatch({
 57	      model: DeploymentModel,
 58	      resource: requestDeployment,
 59	      data: getAttachOBCPatch(obcName, requestDeployment),
 60	    })
 61	      .then((res) => {
 62	        navigate(
 63	          `${resourcePathFromModel(
 64	            DeploymentModel,
 65	            res.metadata.name,
 66	            res.metadata.namespace
 67	          )}/environment`
 68	        );
 69	        closeModal();
 70	      })
 71	      .catch((err) => {
 72	        setErrorMessage(err);
 73	      })
 74	      .finally(() => {
 75	        setProgress(false);
 76	      });
 77	  };
 78	
 79	  const Header = <ModalHeader>{t('Attach OBC to a Deployment')}</ModalHeader>;
 80	
 81	  return (
 82	    <Modal
 83	      header={Header}
 84	      isOpen={isOpen}
 85	      onClose={closeModal}
 86	      showClose={false}
 87	      hasNoBodyWrapper
 88	      variant={ModalVariant.small}
 89	    >
 90	      <ModalBody>
 91	        <div>
 92	          <label
 93	            htmlFor="dropdown-selectbox"
 94	            className="control-label co-required"
 95	          >
 96	            {t('Deployment Name')}
 97	          </label>
 98	        </div>
 99	        <ResourceDropdown<DeploymentKind>
100	          className="odf-deployment__dropdown"
101	          id="dropdown-selectbox"
102	          resource={deploymentResource}
103	          resourceModel={DeploymentModel}
104	          onSelect={(selectedResource) =>
105	            setRequestedDeployment(selectedResource)
106	          }
107	          data-test="dropdown-selectbox"
108	        />
109	        {errorMessage && (
110	          <Alert isInline variant="danger" title={t('An error occurred')}>
111	            {(errorMessage as any)?.message}
112	          </Alert>
113	        )}
114	      </ModalBody>
115	      <ModalFooter>
116	        <Button key="cancel" variant="secondary" onClick={closeModal}>
117	          {t('Cancel')}
118	        </Button>
119	        {!inProgress ? (
120	          <Button
121	            key="Attach"
122	            variant="primary"
123	            onClick={submit}
124	            data-test="attach-action"
125	          >
126	            {t('Attach')}
127	          </Button>
128	        ) : (
129	          <LoadingInline />
130	        )}
131	      </ModalFooter>
132	    </Modal>
133	  );
134	};
135	
136	export default AttachDeploymentToOBCModal;

